db/index.ts.content:
import { Pool, neonConfig } from '@neondatabase/serverless';
import { drizzle } from 'drizzle-orm/neon-serverless';
import ws from "ws";
import * as schema from "./schema";

// Configure WebSocket for Neon
neonConfig.webSocketConstructor = ws;

if (!process.env.DATABASE_URL) {
  throw new Error(
    "DATABASE_URL must be set. Did you forget to provision a database?",
  );
}

// Configure pool with better error handling
export const pool = new Pool({
  connectionString: process.env.DATABASE_URL,
  connectionTimeoutMillis: 5000,
  maxUses: 10000,
  idleTimeoutMillis: 30000,
  max: 10,
});

// Add error handler to the pool
pool.on('error', (err: Error) => {
  console.error('Unexpected error on idle database client', err.stack);
  process.exit(-1);
});

// Export configured drizzle instance
export const db = drizzle({ client: pool, schema });

// Test connection
pool.connect()
  .then(client => {
    console.log('Database connection test successful');
    client.release();
  })
  .catch(err => {
    console.error('Database connection test failed:', err.message);
    process.exit(-1);
  });

db/schema.ts.content:
import { pgTable, text, serial, timestamp, boolean, integer, jsonb } from "drizzle-orm/pg-core";
import { createInsertSchema, createSelectSchema } from "drizzle-zod";
import { z } from "zod";

// Base tables
export const contacts = pgTable("contacts", {
  id: serial("id").primaryKey(),
  name: text("name").notNull(),
  email: text("email").notNull(),
  subject: text("subject").notNull(),
  message: text("message").notNull(),
  createdAt: timestamp("created_at").defaultNow().notNull(),
});

export const newsletters = pgTable("newsletters", {
  id: serial("id").primaryKey(),
  email: text("email").unique().notNull(),
  createdAt: timestamp("created_at").defaultNow().notNull(),
});

export const membershipCount = pgTable("membership_count", {
  id: serial("id").primaryKey(),
  count: integer("count").notNull().default(0),
  updatedAt: timestamp("updated_at").defaultNow().notNull(),
});

export const articles = pgTable("articles", {
  id: serial("id").primaryKey(),
  title: text("title").notNull(),
  author: text("author").notNull(),
  content: text("content").notNull(),
  imageUrl: text("image_url"),
  requirement: text("requirement", {
    enum: ["Free", "Membership"]
  }).notNull().default("Free"),
  createdAt: timestamp("created_at").defaultNow().notNull(),
  updatedAt: timestamp("updated_at").defaultNow().notNull(),
});

export const localArticles = pgTable("local_articles", {
  id: serial("id").primaryKey(),
  title: text("title").notNull(),
  author: text("author").notNull(),
  content: text("content").notNull(),
  imageUrl: text("image_url").notNull(),
  requirement: text("requirement", {
    enum: ["Free", "Membership"]
  }).notNull().default("Free"),
  createdAt: timestamp("created_at").defaultNow().notNull(),
  updatedAt: timestamp("updated_at").defaultNow().notNull(),
});

export const events = pgTable("events", {
  id: serial("id").primaryKey(),
  title: text("title").notNull(),
  description: text("description").notNull(),
  date: timestamp("date").notNull(),
  location: text("location").notNull(),
  type: text("type", {
    enum: ["Conference", "Workshop", "Webinar", "Meetup", "Other"]
  }).notNull(),
  capacity: integer("capacity"),
  registrationRequired: boolean("registration_required").default(false),
  registrationUrl: text("registration_url"),
  imageUrl: text("image_url"),
  organizer: text("organizer").notNull(),
  status: text("status", {
    enum: ["Upcoming", "Ongoing", "Completed", "Cancelled"]
  }).notNull().default("Upcoming"),
  createdAt: timestamp("created_at").defaultNow().notNull(),
  updatedAt: timestamp("updated_at").defaultNow().notNull(),
});

export const users = pgTable("users", {
  id: serial("id").primaryKey(),
  email: text("email").unique().notNull(),
  password: text("password").notNull(),
  name: text("name").notNull(),
  membershipType: text("membership_type", {
    enum: ["Free", "Student", "Full", "Fellow", "Institution"]
  }).notNull().default("Free"),
  membershipStatus: text("membership_status", {
    enum: ["Active", "Inactive", "Pending", "Expired"]
  }).notNull().default("Pending"),
  membershipStartDate: timestamp("membership_start_date"),
  membershipEndDate: timestamp("membership_end_date"),
  organization: text("organization"),
  companyName: text("company_name"),
  companyNumber: text("company_number"),
  contactPerson: text("contact_person"),
  role: text("role"),
  level: text("level", {
    enum: ["admin", "user"]
  }).notNull().default("user"),
  interests: text("interests").array(),
  country: text("country"),
  membership_key: text("membership_key").unique(),
  isActive: boolean("is_active").default(true).notNull(),
  resetToken: text("reset_token").unique(),
  resetTokenExpiry: timestamp("reset_token_expiry"),
  lastLoginAt: timestamp("last_login_at"),
  createdAt: timestamp("created_at").defaultNow().notNull(),
  updatedAt: timestamp("updated_at").defaultNow().notNull(),
});

export const payments = pgTable("payments", {
  id: serial("id").primaryKey(),
  userId: integer("user_id").notNull().references(() => users.id, { foreignKeyName: "fk_user" }),
  amount: text("amount").notNull(),
  currency: text("currency").notNull().default("USD"),
  status: text("status", {
    enum: ["Pending", "Completed", "Failed", "Refunded"]
  }).notNull().default("Pending"),
  paymentMethod: text("payment_method"),
  billingAddress: text("billing_address"),
  createdAt: timestamp("created_at").defaultNow().notNull(),
});

export const admins = pgTable("admins", {
  id: serial("id").primaryKey(),
  username: text("username").unique().notNull(),
  password: text("password").notNull(),
  fullName: text("full_name").notNull(),
  role: text("role", {
    enum: ["super_admin", "content_admin", "member_admin"]
  }).notNull().default("content_admin"),
  isActive: boolean("is_active").default(true),
  resetToken: text("reset_token").unique(),
  resetTokenExpiry: timestamp("reset_token_expiry"),
  lastLoginAt: timestamp("last_login_at"),
  createdAt: timestamp("created_at").defaultNow().notNull(),
  updatedAt: timestamp("updated_at").defaultNow().notNull(),
});

// Schema validations
export const insertContactSchema = createInsertSchema(contacts);
export const selectContactSchema = createSelectSchema(contacts);
export const insertNewsletterSchema = createInsertSchema(newsletters);
export const selectNewsletterSchema = createSelectSchema(newsletters);
export const insertUserSchema = createInsertSchema(users);
export const selectUserSchema = createSelectSchema(users);
export const insertPaymentSchema = createInsertSchema(payments);
export const selectPaymentSchema = createSelectSchema(payments);
export const insertEventSchema = createInsertSchema(events);
export const selectEventSchema = createSelectSchema(events);
export const insertArticleSchema = createInsertSchema(articles);
export const selectArticleSchema = createSelectSchema(articles);
export const insertLocalArticleSchema = createInsertSchema(localArticles);
export const selectLocalArticleSchema = createSelectSchema(localArticles);

export const insertAdminSchema = createInsertSchema(admins, {
  username: z.string().min(3, "Username must be at least 3 characters"),
  password: z.string().min(6, "Password must be at least 6 characters"),
  fullName: z.string().min(2, "Full name must be at least 2 characters"),
  role: z.enum(["super_admin", "content_admin", "member_admin"]),
});

export const selectAdminSchema = createSelectSchema(admins);

// Type definitions
export type InsertContact = typeof contacts.$inferInsert;
export type SelectContact = typeof contacts.$inferSelect;
export type InsertNewsletter = typeof newsletters.$inferInsert;
export type SelectNewsletter = typeof newsletters.$inferSelect;
export type InsertUser = typeof users.$inferInsert;
export type SelectUser = typeof users.$inferSelect;
export type InsertPayment = typeof payments.$inferInsert;
export type SelectPayment = typeof payments.$inferSelect;
export type InsertEvent = typeof events.$inferInsert;
export type SelectEvent = typeof events.$inferSelect;
export type InsertArticle = typeof articles.$inferInsert;
export type SelectArticle = typeof articles.$inferSelect;
export type InsertLocalArticle = typeof localArticles.$inferInsert;
export type SelectLocalArticle = typeof localArticles.$inferSelect;
export type InsertAdmin = typeof admins.$inferInsert;
export type SelectAdmin = typeof admins.$inferSelect;

// Additional validation schemas
export const userRegistrationSchema = z.object({
  email: z.string().email("Invalid email address"),
  password: z.string().min(8, "Password must be at least 8 characters"),
  name: z.string().min(2, "Name must be at least 2 characters"),
  membershipType: z.enum(["Free", "Student", "Full", "Fellow", "Institution"]),
  organization: z.string().optional(),
  companyName: z.string().optional(),
  companyNumber: z.string().optional(),
  contactPerson: z.string().optional(),
  role: z.string().optional(),
  level: z.enum(["admin", "user"]).default("user"),
  interests: z.array(z.string()).optional(),
  country: z.string().optional(),
});

export const paymentProcessSchema = z.object({
  userId: z.number(),
  amount: z.string(),
  currency: z.string().default("USD"),
  paymentMethod: z.string(),
  billingAddress: z.string(),
});

export const eventCreationSchema = z.object({
  title: z.string().min(3, "Title must be at least 3 characters"),
  description: z.string().min(10, "Description must be at least 10 characters"),
  date: z.string().transform((str) => new Date(str)),
  location: z.string(),
  type: z.enum(["Conference", "Workshop", "Webinar", "Meetup", "Other"]),
  capacity: z.number().optional(),
  registrationRequired: z.boolean().default(false),
  // Accept regular URLs or allow empty string
  registrationUrl: z.union([
    z.string().url(),
    z.string().max(0)
  ]).optional(),
  // Accept regular URLs, local file paths, or empty string
  imageUrl: z.union([
    z.string().url(),
    z.string().startsWith("/"),
    z.string().max(0)
  ]).optional(),
  organizer: z.string(),
  status: z.enum(["Upcoming", "Ongoing", "Completed", "Cancelled"]).default("Upcoming"),
});

server/auth.ts.content:
import passport from "passport";
import { Strategy as LocalStrategy } from "passport-local";
import type { Express, Request } from "express";
import { db } from "@db";
import { users, admins } from "@db/schema";
import { eq } from "drizzle-orm";
import { comparePasswords } from "./utils/password";

async function getUserByEmail(email: string) {
  return db.select().from(users).where(eq(users.email, email)).limit(1);
}

async function getAdminByUsername(username: string) {
  return db.select().from(admins).where(eq(admins.username, username)).limit(1);
}

interface AuthError extends Error {
  message: string;
}

import { randomBytes } from 'crypto';
import { generatePasswordResetEmailContent, sendPasswordResetEmail } from './services/email';
import { hashPassword } from './utils/password';

export function setupAuth(app: Express) {
  passport.use(
    new LocalStrategy(
      { usernameField: 'email' },
      async (email: string, password: string, done: (error: AuthError | null, user?: any, info?: { message: string }) => void) => {
        try {
          const [user] = await getUserByEmail(email);
          if (!user || !(await comparePasswords(password, user.password))) {
            return done(null, false, { message: 'Invalid email or password' });
          }
          return done(null, user);
        } catch (error) {
          return done(error as AuthError);
        }
      }
    )
  );

  passport.serializeUser((user: any, done) => {
    done(null, user.id);
  });

  passport.deserializeUser(async (id: number, done) => {
    try {
      const [user] = await db
        .select({
          id: users.id,
          email: users.email,
          role: users.role,
          level: users.level,
          membershipType: users.membershipType,
          membershipStatus: users.membershipStatus,
          membership_key: users.membership_key
        })
        .from(users)
        .where(eq(users.id, id))
        .limit(1);

      if (!user) {
        return done(null, false);
      }
      done(null, user);
    } catch (error) {
      console.error("User deserialization error:", error);
      done(null, false);
    }
  });

  app.use(passport.initialize());
  app.use(passport.session());

  // Login endpoint
  app.post("/api/auth/login", (req: Request, res, next) => {
    passport.authenticate('local', (err: AuthError | null, user: any, info?: { message: string }) => {
      if (err) {
        console.error("Authentication error:", err);
        return next(err);
      }
      if (!user) {
        return res.status(401).json({ message: info?.message || 'Authentication failed' });
      }
      req.logIn(user, (err) => {
        if (err) {
          console.error("Login error:", err);
          return next(err);
        }
        // Return user data without sensitive information
        const { password, ...userData } = user;
        return res.json(userData);
      });
    })(req, res, next);
  });

  // Logout endpoint
  app.post("/api/auth/logout", (req, res) => {
    req.logout((err) => {
      if (err) {
        console.error("Logout error:", err);
        return res.status(500).json({ message: "Error during logout" });
      }
      res.json({ message: "Logged out successfully" });
    });
  });

  // Current user endpoint
  app.get("/api/auth/me", (req, res) => {
    if (req.isAuthenticated()) {
      const user = req.user as any; // Cast to any to access properties
      const isAdmin = user.level === 'admin';
      res.json({
        ...user,
        isAdmin,
      });
    } else {
      res.status(401).json({ message: "Not authenticated" });
    }
  });

  // Forgot password endpoint
  app.post("/api/auth/forgot-password", async (req, res) => {
    try {
      const { email } = req.body;

      if (!email) {
        return res.status(400).json({ message: "Email is required" });
      }

      // Find user by email
      const [user] = await getUserByEmail(email);

      if (!user) {
        // Don't reveal that the user doesn't exist for security reasons
        return res.status(200).json({ 
          message: "If an account with that email exists, a password reset link has been sent" 
        });
      }

      // Generate a reset token
      const resetToken = randomBytes(32).toString('hex');
      const resetTokenExpiry = new Date(Date.now() + 3600000); // 1 hour from now

      // Save token and expiry to user record
      await db.update(users)
        .set({
          resetToken,
          resetTokenExpiry
        })
        .where(eq(users.id, user.id));

      // Generate reset URL
      const resetUrl = `${process.env.FRONTEND_URL || req.headers.origin}/reset-password?token=${resetToken}`;

      // Generate and send email content
      const { html, text } = generatePasswordResetEmailContent(
        user.name,
        resetToken,
        resetUrl
      );

      await sendPasswordResetEmail({
        to: user.email,
        subject: "Password Reset Request",
        html,
        text
      });

      return res.status(200).json({ 
        message: "If an account with that email exists, a password reset link has been sent" 
      });

    } catch (error) {
      console.error("Forgot password error:", error);
      return res.status(500).json({ message: "Error processing your request" });
    }
  });

  // Reset password endpoint
  app.post("/api/auth/reset-password", async (req, res) => {
    try {
      const { token, password } = req.body;

      if (!token || !password) {
        return res.status(400).json({ message: "Token and password are required" });
      }

      // Find user by reset token
      const [user] = await db.select()
        .from(users)
        .where(eq(users.resetToken, token))
        .limit(1);

      if (!user) {
        return res.status(400).json({ message: "Invalid or expired token" });
      }

      // Check if token is expired
      if (!user.resetTokenExpiry || new Date(user.resetTokenExpiry) < new Date()) {
        return res.status(400).json({ message: "Token has expired" });
      }

      // Hash the new password
      const hashedPassword = await hashPassword(password);

      // Update user with new password and clear reset token
      await db.update(users)
        .set({
          password: hashedPassword,
          resetToken: null,
          resetTokenExpiry: null
        })
        .where(eq(users.id, user.id));

      return res.status(200).json({ message: "Password has been reset successfully" });

    } catch (error) {
      console.error("Reset password error:", error);
      return res.status(500).json({ message: "Error processing your request" });
    }
  });

  // Admin forgot password endpoint
  app.post("/api/admin/forgot-password", async (req, res) => {
    try {
      const { username } = req.body;

      if (!username) {
        return res.status(400).json({ message: "Username is required" });
      }

      // Find admin by username
      const [admin] = await getAdminByUsername(username);

      if (!admin) {
        // Don't reveal that the admin doesn't exist for security reasons
        return res.status(200).json({ 
          message: "If an account with that username exists, a password reset link has been sent" 
        });
      }

      // Generate a reset token
      const resetToken = randomBytes(32).toString('hex');
      const resetTokenExpiry = new Date(Date.now() + 3600000); // 1 hour from now

      // Save token and expiry to admin record
      await db.update(admins)
        .set({
          resetToken,
          resetTokenExpiry
        })
        .where(eq(admins.id, admin.id));

      // Generate reset URL
      const resetUrl = `${process.env.FRONTEND_URL || req.headers.origin}/admin/reset-password?token=${resetToken}`;

      // Generate and send email content
      const { html, text } = generatePasswordResetEmailContent(
        admin.fullName,
        resetToken,
        resetUrl
      );

      await sendPasswordResetEmail({
        to: admin.username, // Assuming username is the email for admins
        subject: "Admin Password Reset Request",
        html,
        text
      });

      return res.status(200).json({ 
        message: "If an account with that username exists, a password reset link has been sent" 
      });

    } catch (error) {
      console.error("Admin forgot password error:", error);
      return res.status(500).json({ message: "Error processing your request" });
    }
  });

  // Admin reset password endpoint
  app.post("/api/admin/reset-password", async (req, res) => {
    try {
      const { token, password } = req.body;

      if (!token || !password) {
        return res.status(400).json({ message: "Token and password are required" });
      }

      // Find admin by reset token
      const [admin] = await db.select()
        .from(admins)
        .where(eq(admins.resetToken, token))
        .limit(1);

      if (!admin) {
        return res.status(400).json({ message: "Invalid or expired token" });
      }

      // Check if token is expired
      if (!admin.resetTokenExpiry || new Date(admin.resetTokenExpiry) < new Date()) {
        return res.status(400).json({ message: "Token has expired" });
      }

      // Hash the new password
      const hashedPassword = await hashPassword(password);

      // Update admin with new password and clear reset token
      await db.update(admins)
        .set({
          password: hashedPassword,
          resetToken: null,
          resetTokenExpiry: null
        })
        .where(eq(admins.id, admin.id));

      return res.status(200).json({ message: "Password has been reset successfully" });

    } catch (error) {
      console.error("Admin reset password error:", error);
      return res.status(500).json({ message: "Error processing your request" });
    }
  });
}

