import { randomInt } from 'crypto';

export type MembershipType = 'Student Member' | 'Full Member' | 'Institutional Member' | 'Free Membership';

export function generateMemberKey(membershipType: MembershipType): string {
  // Get current year's last two digits
  const year = new Date().getFullYear().toString().slice(-2);

  // Generate 4 random numbers
  const randomNumbers = Array.from({ length: 4 }, () => randomInt(0, 10)).join('');

  // Determine letter based on membership type
  let letter: string;
  switch (membershipType) {
    case 'Student Member':
      letter = 'S';
      break;
    case 'Full Member':
      letter = 'F';
      break;
    case 'Institutional Member':
      letter = 'I';
      break;
    default:
      letter = 'N'; // N for None/Free membership
  }

  // Return formatted key
  return `${year}-${randomNumbers}-${letter}`;
}

server/utils/password.ts.content:
import { scrypt, randomBytes } from "crypto";
import { promisify } from "util";

const scryptAsync = promisify(scrypt);

/**
 * Hash a password with a random salt
 * @param password The plain text password to hash
 * @returns A string in the format "hash.salt"
 */
export async function hashPassword(password: string): Promise<string> {
  const salt = randomBytes(16).toString("hex");
  const buf = (await scryptAsync(password, salt, 64)) as Buffer;
  return `${buf.toString("hex")}.${salt}`;
}

/**
 * Compare a supplied password with a stored hashed password
 * @param supplied The plain text password to compare
 * @param stored The stored hashed password
 * @returns Boolean indicating if the passwords match
 */
export async function comparePasswords(supplied: string, stored: string): Promise<boolean> {
  try {
    const [hashed, salt] = stored.split(".");
    if (!salt) {
      return false; // Invalid stored password format
    }
    const hashedBuf = Buffer.from(hashed, "hex");
    const suppliedBuf = (await scryptAsync(supplied, salt, 64)) as Buffer;
    return Buffer.compare(hashedBuf, suppliedBuf) === 0;
  } catch (error) {
    console.error("Password comparison error:", error);
    return false;
  }
}

