} from "@/components/ui/select";
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "@/components/ui/form";
import { zodResolver } from "@hookform/resolvers/zod";
import { useForm } from "react-hook-form";
import { z } from "zod";
import { Checkbox } from "@/components/ui/checkbox";
import { Badge } from "@/components/ui/badge";
import { Separator } from "@/components/ui/separator";
import {
  X,
  Edit,
  Plus,
  Trash2,
  ChevronLeft,
  Upload,
  Image as ImageIcon,
} from "lucide-react";
import { apiRequest } from "@/lib/queryClient";
import { format, parseISO } from "date-fns";
import { useAdminAuth } from "@/hooks/use-admin-auth";
import { ProtectedAdminRoute } from "@/components/auth/protected-admin-route";
import { Link } from "wouter";
import { AspectRatio } from "@/components/ui/aspect-ratio";

// Create form schema based on the event schema
const formSchema = z.object({
  title: z.string().min(3, "Title must be at least 3 characters"),
  description: z.string().min(10, "Description must be at least 10 characters"),
  date: z.string().min(1, "Date is required"),
  location: z.string().min(1, "Location is required"),
  type: z.enum(["Conference", "Workshop", "Webinar", "Meetup", "Other"]),
  capacity: z
    .union([z.number(), z.string()])
    .optional()
    .transform((val) => {
      if (typeof val === "string" && val !== "") {
        return parseInt(val);
      }
      if (typeof val === "number") {
        return val;
      }
      return undefined;
    }),
  registrationRequired: z.boolean().default(false),
  registrationUrl: z.string().url().optional().or(z.literal("")),
  // Accept both URLs and local file paths for images
  imageUrl: z.string().optional().or(z.literal("")),
  organizer: z.string().min(1, "Organizer is required"),
  status: z
    .enum(["Upcoming", "Ongoing", "Completed", "Cancelled"])
    .default("Upcoming"),
});

type FormData = z.infer<typeof formSchema>;

export default function EventsPage() {
  const { admin } = useAdminAuth();
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const [isDeleteDialogOpen, setIsDeleteDialogOpen] = useState(false);
  const [currentEvent, setCurrentEvent] = useState<SelectEvent | null>(null);
  const [imageFile, setImageFile] = useState<File | null>(null);
  const [imagePreview, setImagePreview] = useState<string | null>(null);
  const [isUploading, setIsUploading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Query for fetching events
  const { data: events, isLoading } = useQuery({
    queryKey: ["/api/admin/events"],
    queryFn: async () => {
      const response = await fetch("/api/admin/events");
      if (!response.ok) {
        throw new Error("Failed to fetch events");
      }
      return response.json();
    },
    enabled: !!admin,
  });

  // Form setup
  const form = useForm<FormData>({
    resolver: zodResolver(formSchema),
    defaultValues: {
      title: "",
      description: "",
      date: "",
      location: "",
      type: "Conference",
      capacity: undefined,
      registrationRequired: false,
      registrationUrl: "",
      imageUrl: "",
      organizer: "",
      status: "Upcoming",
    },
  });

  // Edit event mutation
  const editMutation = useMutation({
    mutationFn: async (data: FormData) => {
      if (!currentEvent) return null;
      const response = await apiRequest(
        "PUT",
        `/api/admin/events/${currentEvent.id}`,
        data,
      );
      return response;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/admin/events"] });
      toast({
        title: "Event Updated",
        description: "The event has been updated successfully.",
      });
      setIsDialogOpen(false);
      setCurrentEvent(null);
      form.reset();
    },
    onError: (error) => {
      toast({
        title: "Error",
        description: `Failed to update event: ${error.message}`,
        variant: "destructive",
      });
    },
  });

  // Create event mutation
  const createMutation = useMutation({
    mutationFn: async (data: FormData) => {
      const response = await apiRequest("POST", "/api/admin/events", data);
      return response;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/admin/events"] });
      toast({
        title: "Event Created",
        description: "The event has been created successfully.",
      });
      setIsDialogOpen(false);
      form.reset();
    },
    onError: (error) => {
      toast({
        title: "Error",
        description: `Failed to create event: ${error.message}`,
        variant: "destructive",
      });
    },
  });

  // Upload image mutation
  const uploadImageMutation = useMutation({
    mutationFn: async (file: File) => {
      setIsUploading(true);
      const formData = new FormData();
      formData.append("image", file);

      const response = await fetch("/api/admin/event-image-upload", {
        method: "POST",
        body: formData,
      });

      if (!response.ok) {
        const error = await response.json();
        throw new Error(error.error || "Failed to upload image");
      }

      return response.json();
    },
    onSuccess: (data) => {
      if (data.success && data.imagePath) {
        form.setValue("imageUrl", data.imagePath);
        setIsUploading(false);
        toast({
          title: "Image Uploaded",
          description: "Event image was uploaded successfully.",
        });
      }
    },
    onError: (error) => {
      setIsUploading(false);
      toast({
        title: "Upload Failed",
        description: `Failed to upload image: ${error.message}`,
        variant: "destructive",
      });
    },
  });

  // Delete event mutation
  const deleteMutation = useMutation({
    mutationFn: async (id: number) => {
      const response = await apiRequest("DELETE", `/api/admin/events/${id}`);
      return response;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/admin/events"] });
      toast({
        title: "Event Deleted",
        description: "The event has been deleted successfully.",
      });
      setIsDeleteDialogOpen(false);
      setCurrentEvent(null);
    },
    onError: (error) => {
      toast({
        title: "Error",
        description: `Failed to delete event: ${error.message}`,
        variant: "destructive",
      });
    },
  });

  const onOpenCreateDialog = () => {
    setCurrentEvent(null);
    form.reset({
      title: "",
      description: "",
      date: "",
      location: "",
      type: "Conference",
      capacity: undefined,
      registrationRequired: false,
      registrationUrl: "",
      imageUrl: "",
      organizer: "",
      status: "Upcoming",
    });
    setIsDialogOpen(true);
  };

  const onOpenEditDialog = (event: SelectEvent) => {
    setCurrentEvent(event);
    form.reset({
      title: event.title,
      description: event.description,
      date: format(new Date(event.date), "yyyy-MM-dd'T'HH:mm"),
      location: event.location,
      type: event.type as
        | "Conference"
        | "Workshop"
        | "Webinar"
        | "Meetup"
        | "Other",
      capacity: typeof event.capacity === "number" ? event.capacity : undefined,
      registrationRequired: event.registrationRequired || false,
      registrationUrl: event.registrationUrl || "",
      imageUrl: event.imageUrl || "",
      organizer: event.organizer,
      status: event.status as
        | "Upcoming"
        | "Ongoing"
        | "Completed"
        | "Cancelled",
    });
    setIsDialogOpen(true);
  };

  const onOpenDeleteDialog = (event: SelectEvent) => {
    setCurrentEvent(event);
    setIsDeleteDialogOpen(true);
  };

  // Image file handling
  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (files && files.length > 0) {
      const file = files[0];
      setImageFile(file);

      // Create a preview
      const reader = new FileReader();
      reader.onloadend = () => {
        setImagePreview(reader.result as string);
      };
      reader.readAsDataURL(file);

      // Upload the file
      uploadImageMutation.mutate(file);
    }
  };

  // Reset image state when dialog is closed
  useEffect(() => {
    if (!isDialogOpen) {
      setImageFile(null);
      setImagePreview(null);
    } else if (currentEvent?.imageUrl) {
      // Set preview for editing existing event with image
      setImagePreview(currentEvent.imageUrl);
    }
  }, [isDialogOpen, currentEvent]);

  const onSubmit = (data: FormData) => {
    if (currentEvent) {
      editMutation.mutate(data);
    } else {
      createMutation.mutate(data);
    }
  };

  const getStatusBadgeVariant = (
    status: string,
  ):
    | "default"
    | "secondary"
    | "destructive"
    | "outline"
    | "success"
    | "warning" => {
    switch (status) {
      case "Upcoming":
        return "success";
      case "Ongoing":
        return "warning";
      case "Completed":
        return "secondary";
      case "Cancelled":
        return "destructive";
      default:
        return "default";
    }
  };

  return (
    <div className="container py-10">
      <div className="flex items-center mb-6">
        <h1 className="text-3xl font-bold">Events Management</h1>
      </div>

      <div className="flex justify-end mb-6">
        <Button variant="outline" asChild className="mr-4">
          <Link href="/admin/dashboard" className="flex items-center gap-2">
            <ChevronLeft size={16} /> Back to Dashboard
          </Link>
        </Button>

        <Button onClick={onOpenCreateDialog} className="gap-2">
          <Plus size={16} /> Add New Event
        </Button>
      </div>

      <Separator className="my-6" />

      {isLoading ? (
        <div className="flex items-center justify-center h-64">
          <div className="text-lg">Loading events...</div>
        </div>
      ) : (
        <div className="rounded-md border flex items-center justify-center ml-24">
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>Title</TableHead>
                <TableHead>Date</TableHead>
                <TableHead>Location</TableHead>
                <TableHead>Type</TableHead>
                <TableHead>Status</TableHead>
                <TableHead className="text-right">Actions</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {events && events.length > 0 ? (
                events.map((event: SelectEvent) => (
                  <TableRow key={event.id}>
                    <TableCell className="font-medium">{event.title}</TableCell>
                    <TableCell>
                      {format(new Date(event.date), "MMM d, yyyy h:mm a")}
                    </TableCell>
                    <TableCell>{event.location}</TableCell>
                    <TableCell>{event.type}</TableCell>
                    <TableCell>
                      <Badge variant={getStatusBadgeVariant(event.status)}>
                        {event.status}
                      </Badge>
                    </TableCell>
                    <TableCell className="text-right">
                      <div className="flex justify-end gap-2">
                        <Button
                          variant="ghost"
                          size="icon"
                          onClick={() => onOpenEditDialog(event)}
                        >
                          <Edit size={16} />
                        </Button>
                        <Button
                          variant="ghost"
                          size="icon"
                          onClick={() => onOpenDeleteDialog(event)}
                        >
                          <Trash2 size={16} />
                        </Button>
                      </div>
                    </TableCell>
                  </TableRow>
                ))
              ) : (
                <TableRow>
                  <TableCell colSpan={6} className="text-center py-6">
                    No events found. Click "Add New Event" to create one.
                  </TableCell>
                </TableRow>
              )}
            </TableBody>
          </Table>
        </div>
      )}

      {/* Create/Edit Event Dialog */}
      <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
        <DialogContent className="sm:max-w-[700px] max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>
              {currentEvent ? "Edit Event" : "Create New Event"}
            </DialogTitle>
          </DialogHeader>

          <Form {...form}>
            <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <FormField
                  control={form.control}
                  name="title"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Title</FormLabel>
                      <FormControl>
                        <Input placeholder="Event title" {...field} />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="date"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Date and Time</FormLabel>
                      <FormControl>
                        <Input type="datetime-local" {...field} />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="location"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Location</FormLabel>
                      <FormControl>
                        <Input placeholder="Event location" {...field} />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="type"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Event Type</FormLabel>
                      <Select
                        onValueChange={field.onChange}
                        defaultValue={field.value}
                      >
                        <FormControl>
                          <SelectTrigger>
                            <SelectValue placeholder="Select event type" />
                          </SelectTrigger>
                        </FormControl>
                        <SelectContent>
                          <SelectItem value="Conference">Conference</SelectItem>
                          <SelectItem value="Workshop">Workshop</SelectItem>
                          <SelectItem value="Webinar">Webinar</SelectItem>
                          <SelectItem value="Meetup">Meetup</SelectItem>
                          <SelectItem value="Other">Other</SelectItem>
                        </SelectContent>
                      </Select>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="organizer"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Organizer</FormLabel>
                      <FormControl>
                        <Input placeholder="Event organizer" {...field} />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="status"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Status</FormLabel>
                      <Select
                        onValueChange={field.onChange}
                        defaultValue={field.value}
                      >
                        <FormControl>
                          <SelectTrigger>
                            <SelectValue placeholder="Select status" />
                          </SelectTrigger>
                        </FormControl>
                        <SelectContent>
                          <SelectItem value="Upcoming">Upcoming</SelectItem>
                          <SelectItem value="Ongoing">Ongoing</SelectItem>
                          <SelectItem value="Completed">Completed</SelectItem>
                          <SelectItem value="Cancelled">Cancelled</SelectItem>
                        </SelectContent>
                      </Select>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="capacity"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Capacity (optional)</FormLabel>
                      <FormControl>
                        <Input
                          type="number"
                          placeholder="Maximum attendees"
                          {...field}
                        />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="imageUrl"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Event Image</FormLabel>
                      <div className="space-y-4">
                        <div className="flex items-center gap-4">
                          <Input type="hidden" {...field} />
                          <Button
                            type="button"
                            variant="outline"
                            className="flex items-center gap-2"
                            onClick={() => fileInputRef.current?.click()}
                            disabled={isUploading}
                          >
                            {isUploading ? "Uploading..." : "Upload Image"}
                            <Upload size={16} />
                          </Button>
                          <input
                            type="file"
                            accept="image/*"
                            className="hidden"
                            ref={fileInputRef}
                            onChange={handleFileChange}
                          />
                        </div>

                        {imagePreview ? (
                          <div className="border rounded-md overflow-hidden w-full max-w-sm">
                            <AspectRatio ratio={16 / 9}>
                              <img
                                src={imagePreview}
                                alt="Event image preview"
                                className="w-full h-full object-cover"
                              />
                            </AspectRatio>
                          </div>
                        ) : (
                          <div className="border rounded-md flex items-center justify-center w-full max-w-sm bg-muted/20">
                            <AspectRatio ratio={16 / 9}>
                              <div className="flex flex-col items-center justify-center text-muted-foreground">
                                <ImageIcon size={48} strokeWidth={1} />
                                <p className="text-sm mt-2">
                                  No image selected
                                </p>
                              </div>
                            </AspectRatio>
                          </div>
                        )}
                      </div>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <div className="col-span-1 md:col-span-2">
                  <FormField
                    control={form.control}
                    name="registrationRequired"
                    render={({ field }) => (
                      <FormItem className="flex flex-row items-start space-x-3 space-y-0 rounded-md border p-4">
                        <FormControl>
                          <Checkbox
                            checked={field.value}
                            onCheckedChange={field.onChange}
                          />
                        </FormControl>
                        <div className="space-y-1 leading-none">
                          <FormLabel>Registration Required</FormLabel>
                        </div>
                      </FormItem>
                    )}
                  />
                </div>

                {form.watch("registrationRequired") && (
                  <div className="col-span-1 md:col-span-2">
                    <FormField
                      control={form.control}
                      name="registrationUrl"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Registration URL</FormLabel>
                          <FormControl>
                            <Input
                              placeholder="https://example.com/register"
                              {...field}
                            />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                  </div>
                )}

                <div className="col-span-1 md:col-span-2">
                  <FormField
                    control={form.control}
                    name="description"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Description</FormLabel>
                        <FormControl>
                          <Textarea
                            placeholder="Event description"
                            className="min-h-32"
                            {...field}
                          />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                </div>
              </div>

              <DialogFooter>
                <Button
                  type="button"
                  variant="outline"
                  onClick={() => setIsDialogOpen(false)}
                >
                  Cancel
                </Button>
                <Button
                  type="submit"
                  disabled={createMutation.isPending || editMutation.isPending}
                >
                  {createMutation.isPending || editMutation.isPending
                    ? "Saving..."
                    : currentEvent
                      ? "Update Event"
                      : "Create Event"}
                </Button>
              </DialogFooter>
            </form>
          </Form>
        </DialogContent>
      </Dialog>

      {/* Delete Confirmation Dialog */}
      <Dialog open={isDeleteDialogOpen} onOpenChange={setIsDeleteDialogOpen}>
        <DialogContent className="sm:max-w-[425px]">
          <DialogHeader>
            <DialogTitle>Confirm Deletion</DialogTitle>
          </DialogHeader>
          <div className="py-4">
            <p>
              Are you sure you want to delete the event "
              <strong>{currentEvent?.title}</strong>"? This action cannot be
              undone.
            </p>
          </div>
          <DialogFooter>
            <Button
              type="button"
              variant="outline"
              onClick={() => setIsDeleteDialogOpen(false)}
            >
              Cancel
            </Button>
            <Button
              type="button"
              variant="destructive"
              onClick={() =>
                currentEvent && deleteMutation.mutate(currentEvent.id)
              }
              disabled={deleteMutation.isPending}
            >
              {deleteMutation.isPending ? "Deleting..." : "Delete Event"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

client/src/pages/admin/forgot-password.t.content:
import { useState } from "react";
import { z } from "zod";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { useMutation } from "@tanstack/react-query";
import { apiRequest } from "../../lib/queryClient";
import { useToast } from "@/hooks/use-toast";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { AlertCircle, ArrowLeft, CheckCircle2 } from "lucide-react";
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert";
import { Link } from "wouter";

const forgotPasswordSchema = z.object({
  username: z.string().min(1, "Username is required"),
});

type ForgotPasswordFormData = z.infer<typeof forgotPasswordSchema>;

export default function AdminForgotPassword() {
  const { toast } = useToast();
  const [emailSent, setEmailSent] = useState(false);

  const form = useForm<ForgotPasswordFormData>({
    resolver: zodResolver(forgotPasswordSchema),
    defaultValues: {
      username: "",
    },
  });

  const forgotPasswordMutation = useMutation({
    mutationFn: async (data: ForgotPasswordFormData) => {
      return await apiRequest('POST', '/api/admin/forgot-password', data);
    },
    onSuccess: () => {
      setEmailSent(true);
      toast({
        title: "Email Sent",
        description: "If an account with that username exists, you will receive password reset instructions",
      });
    },
    onError: (error: Error) => {
      toast({
        title: "Error",
        description: error.message || "Failed to process your request",
        variant: "destructive",
      });
    },
  });

  function onSubmit(data: ForgotPasswordFormData) {
    forgotPasswordMutation.mutate(data);
  }

  return (
    <div className="container max-w-lg py-10">
      <Card>
        <CardHeader className="space-y-1">
          <CardTitle className="text-2xl">Forgot Admin Password</CardTitle>
          <CardDescription>
            Enter your admin username and we'll send you a link to reset your password
          </CardDescription>
        </CardHeader>
        <CardContent>
          {emailSent ? (
            <>
              <Alert className="mb-4 bg-green-50">
                <CheckCircle2 className="h-4 w-4 text-green-600" />
                <AlertTitle>Check your email</AlertTitle>
                <AlertDescription>
                  We've sent you an email with instructions to reset your password.
                  Please check your inbox and spam folder.
                </AlertDescription>
              </Alert>
              <Button variant="outline" className="w-full" asChild>
                <Link href="/">
                  <ArrowLeft className="mr-2 h-4 w-4" />
                  Back to Home
                </Link>
              </Button>
            </>
          ) : (
            <Form {...form}>
              <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-4">
                <FormField
                  control={form.control}
                  name="username"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Admin Username</FormLabel>
                      <FormControl>
                        <Input 
                          placeholder="Your admin username" 
                          {...field}
                        />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                {forgotPasswordMutation.isError && (
                  <Alert variant="destructive">
                    <AlertCircle className="h-4 w-4" />
                    <AlertTitle>Error</AlertTitle>
                    <AlertDescription>
                      {forgotPasswordMutation.error?.message || "Failed to process your request"}
                    </AlertDescription>
                  </Alert>
                )}

                <Button 
                  type="submit" 
                  className="w-full"
                  disabled={forgotPasswordMutation.isPending}
                >
                  {forgotPasswordMutation.isPending ? (
                    <>
                      <span className="mr-2 h-4 w-4 animate-spin">&#9696;</span>
                      Sending...
                    </>
                  ) : (
                    "Send Reset Link"
                  )}
                </Button>

                <div className="text-center text-sm">
                  <Link href="/" className="text-blue-600 hover:underline">
                    Back to Home
                  </Link>
                </div>
              </form>
            </Form>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

client/src/pages/admin/local-articles.ts.content:
import { useState, useRef } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { useToast } from "@/hooks/use-toast";
import { Button } from "@/components/ui/button";
import { SelectLocalArticle } from "@db/schema";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import {
  Dialog,
  DialogContent,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
  FormDescription,
} from "@/components/ui/form";
import { zodResolver } from "@hookform/resolvers/zod";
import { useForm } from "react-hook-form";
import { z } from "zod";
import { Badge } from "@/components/ui/badge";
import { Separator } from "@/components/ui/separator";
import {
  Edit,
  Plus,
  Trash2,
  ChevronLeft,
  Upload,
  Image as ImageIcon,
  X,
} from "lucide-react";
import { Link } from "wouter";
import { apiRequest } from "@/lib/queryClient";
import { format } from "date-fns";
import { useAdminAuth } from "@/hooks/use-admin-auth";
import { AspectRatio } from "@/components/ui/aspect-ratio";

// Form schema
const formSchema = z.object({
  title: z.string().min(3, "Title must be at least 3 characters"),
  author: z.string().min(3, "Author must be at least 3 characters"),
  content: z.string().min(10, "Content must be at least 10 characters"),
  // Accept both URLs and relative paths for images
  imageUrl: z.string().optional().or(z.literal("")),
  requirement: z.enum(["Free", "Membership"]).default("Free"),
});

type FormData = z.infer<typeof formSchema>;

export default function LocalArticlesPage() {
  const { admin } = useAdminAuth();
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const [isDeleteDialogOpen, setIsDeleteDialogOpen] = useState(false);
  const [currentArticle, setCurrentArticle] =
    useState<SelectLocalArticle | null>(null);
  const [imageFile, setImageFile] = useState<File | null>(null);
  const [imagePreview, setImagePreview] = useState<string | null>(null);
  const [isUploading, setIsUploading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Query for fetching local articles
  const { data: articles, isLoading } = useQuery({
    queryKey: ["/api/admin/local-articles"],
    queryFn: async () => {
      const response = await fetch("/api/admin/local-articles");
      if (!response.ok) {
        throw new Error("Failed to fetch local articles");
      }
      return response.json();
    },
    enabled: !!admin,
  });

  // Form setup
  const form = useForm<FormData>({
    resolver: zodResolver(formSchema),
    defaultValues: {
      title: "",
      author: "",
      content: "",
      imageUrl: "",
      requirement: "Free",
    },
  });

  // Edit article mutation
  const editMutation = useMutation({
    mutationFn: async (data: FormData) => {
      if (!currentArticle) return null;
      const response = await apiRequest(
        "PUT",
        `/api/admin/local-articles/${currentArticle.id}`,
        data,
      );
      return response;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({
        queryKey: ["/api/admin/local-articles"],
      });
      queryClient.invalidateQueries({ queryKey: ["/api/local-articles"] });
      toast({
        title: "Local Article Updated",
        description: "The local article has been updated successfully.",
      });
      setIsDialogOpen(false);
      setCurrentArticle(null);
      form.reset();
    },
    onError: (error) => {
      toast({
        title: "Error",
        description: `Failed to update local article: ${error.message}`,
        variant: "destructive",
      });
    },
  });

  // Create article mutation
  const createMutation = useMutation({
    mutationFn: async (data: FormData) => {
      const response = await apiRequest(
        "POST",
        "/api/admin/local-articles",
        data,
      );
      return response;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({
        queryKey: ["/api/admin/local-articles"],
      });
      queryClient.invalidateQueries({ queryKey: ["/api/local-articles"] });
      toast({
        title: "Local Article Created",
        description: "The local article has been created successfully.",
      });
      setIsDialogOpen(false);
      form.reset();
    },
    onError: (error) => {
      toast({
        title: "Error",
        description: `Failed to create local article: ${error.message}`,
        variant: "destructive",
      });
    },
  });

  // Delete article mutation
  const deleteMutation = useMutation({
    mutationFn: async (id: number) => {
      const response = await apiRequest(
        "DELETE",
        `/api/admin/local-articles/${id}`,
      );
      return response;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({
        queryKey: ["/api/admin/local-articles"],
      });
      queryClient.invalidateQueries({ queryKey: ["/api/local-articles"] });
      toast({
        title: "Local Article Deleted",
        description: "The local article has been deleted successfully.",
      });
      setIsDeleteDialogOpen(false);
      setCurrentArticle(null);
    },
    onError: (error) => {
      toast({
        title: "Error",
        description: `Failed to delete local article: ${error.message}`,
        variant: "destructive",
      });
    },
  });

  // Upload image mutation
  const uploadImageMutation = useMutation({
    mutationFn: async (file: File) => {
      setIsUploading(true);
      const formData = new FormData();
      formData.append("image", file);

      const response = await fetch("/api/admin/article-image-upload", {
        method: "POST",
        body: formData,
      });

      if (!response.ok) {
        const error = await response.json();
        throw new Error(error.error || "Failed to upload image");
      }

      return response.json();
    },
    onSuccess: (data) => {
      if (data.success && data.imagePath) {
        form.setValue("imageUrl", data.imagePath);
        toast({
          title: "Image Uploaded",
          description: "The image has been uploaded successfully.",
        });
      }
      setIsUploading(false);
    },
    onError: (error) => {
      toast({
        title: "Error",
        description: `Failed to upload image: ${error.message}`,
        variant: "destructive",
      });
      setIsUploading(false);
    },
  });

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (files && files.length > 0) {
      const file = files[0];
      setImageFile(file);

      // Create a preview
      const reader = new FileReader();
      reader.onloadend = () => {
        setImagePreview(reader.result as string);
      };
      reader.readAsDataURL(file);

      // Upload the file
      uploadImageMutation.mutate(file);
    }
  };

  const clearImagePreview = () => {
    setImagePreview(null);
    setImageFile(null);
    if (fileInputRef.current) {
      fileInputRef.current.value = "";
    }
  };

  const onOpenCreateDialog = () => {
    setCurrentArticle(null);
    form.reset({
      title: "",
      author: "",
      content: "",
      imageUrl: "",
      requirement: "Free",
    });
    setImagePreview(null);
    setImageFile(null);
    setIsDialogOpen(true);
  };

  const onOpenEditDialog = (article: SelectLocalArticle) => {
    setCurrentArticle(article);
    form.reset({
      title: article.title,
      author: article.author,
      content: article.content,
      imageUrl: article.imageUrl || "",
      requirement: article.requirement as "Free" | "Membership",
    });

    // Set image preview if there's an existing image URL
    // For existing images, use the absolute path for preview
    if (article.imageUrl) {
      setImagePreview(
        article.imageUrl.startsWith("http")
          ? article.imageUrl
          : article.imageUrl,
      );
    } else {
      setImagePreview(null);
    }

    setImageFile(null);
    setIsDialogOpen(true);
  };

  const onOpenDeleteDialog = (article: SelectLocalArticle) => {
    setCurrentArticle(article);
    setIsDeleteDialogOpen(true);
  };

  const onSubmit = (data: FormData) => {
    if (currentArticle) {
      editMutation.mutate(data);
    } else {
      createMutation.mutate(data);
    }
  };

  return (
    <div className="container py-10  mx-auto">
      <div className="flex flex-col items-center mb-6">
        <h1 className="text-3xl font-bold mb-4">Local Articles Management</h1>

        <div className="flex gap-4 w-full justify-center">
          <Button variant="outline" asChild>
            <Link href="/admin/dashboard" className="flex items-center gap-2">
              <ChevronLeft size={16} /> Back to Dashboard
            </Link>
          </Button>

          <Button onClick={onOpenCreateDialog} className="gap-2">
            <Plus size={16} /> Add New Local Article
          </Button>
        </div>
      </div>

      <Separator className="my-6" />

      {isLoading ? (
        <div className="flex items-center justify-center h-64">
          <div className="text-lg">Loading local articles...</div>
        </div>
      ) : (
        <div className="rounded-md border">
          <Table style={{ width: "100%" }}>
            <TableHeader>
              <TableRow>
                <TableHead>Title</TableHead>
                <TableHead>Author</TableHead>
                <TableHead>Requirement</TableHead>
                <TableHead>Created</TableHead>
                <TableHead className="text-right">Actions</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {articles && articles.length > 0 ? (
                articles.map((article: SelectLocalArticle) => (
                  <TableRow key={article.id}>
                    <TableCell className="font-medium">
                      {article.title}
                    </TableCell>
                    <TableCell>{article.author}</TableCell>
                    <TableCell>
                      <Badge
                        variant={
                          article.requirement === "Free"
                            ? "default"
                            : "secondary"
                        }
                      >
                        {article.requirement}
                      </Badge>
                    </TableCell>
                    <TableCell>
                      {format(new Date(article.createdAt), "MMM d, yyyy")}
                    </TableCell>
                    <TableCell className="text-right">
                      <div className="flex justify-end gap-2">
                        <Button
                          variant="ghost"
                          size="icon"
                          onClick={() => onOpenEditDialog(article)}
                        >
                          <Edit size={16} />
                        </Button>
                        <Button
                          variant="ghost"
                          size="icon"
                          onClick={() => onOpenDeleteDialog(article)}
                        >
                          <Trash2 size={16} />
                        </Button>
                      </div>
                    </TableCell>
                  </TableRow>
                ))
              ) : (
                <TableRow>
                  <TableCell colSpan={5} className="text-center py-6">
                    No local articles found. Click "Add New Local Article" to
                    create one.
                  </TableCell>
                </TableRow>
              )}
            </TableBody>
          </Table>
        </div>
      )}

      {/* Create/Edit Article Dialog */}
      <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
        <DialogContent className="sm:max-w-[700px] max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>
              {currentArticle
                ? "Edit Local Article"
                : "Create New Local Article"}
            </DialogTitle>
          </DialogHeader>

          <Form {...form}>
            <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <FormField
                  control={form.control}
                  name="title"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Title</FormLabel>
                      <FormControl>
                        <Input placeholder="Article title" {...field} />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="author"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Author</FormLabel>
                      <FormControl>
                        <Input placeholder="Author name" {...field} />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="requirement"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Access Requirement</FormLabel>
                      <Select
                        onValueChange={field.onChange}
                        defaultValue={field.value}
                      >
                        <FormControl>
                          <SelectTrigger>
                            <SelectValue placeholder="Select requirement" />
                          </SelectTrigger>
                        </FormControl>
                        <SelectContent>
                          <SelectItem value="Free">Free</SelectItem>
                          <SelectItem value="Membership">Membership</SelectItem>
                        </SelectContent>
                      </Select>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <div className="space-y-4">
                  <FormField
                    control={form.control}
                    name="imageUrl"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Image URL</FormLabel>
                        <FormControl>
                          <Input
                            placeholder="URL will be auto-populated when image is uploaded"
                            {...field}
                            readOnly
                          />
                        </FormControl>
                        <FormDescription>
                          Use the image uploader below to add an image
                        </FormDescription>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <div className="space-y-4">
                    <div className="flex items-center gap-4">
                      <Button
                        type="button"
                        className="gap-2"
                        variant="outline"
                        onClick={() => fileInputRef.current?.click()}
                        disabled={isUploading}
                      >
                        <Upload size={16} />
                        {isUploading ? "Uploading..." : "Upload Image"}
                      </Button>
                      {imagePreview && (
                        <Button
                          type="button"
                          variant="ghost"
                          size="icon"
                          onClick={clearImagePreview}
                          className="text-destructive"
                        >
                          <X size={16} />
                        </Button>
                      )}
                    </div>

                    <input
                      type="file"
                      accept="image/png,image/jpeg,image/jpg,image/webp"
                      className="hidden"
                      ref={fileInputRef}
                      onChange={handleFileChange}
                    />

                    {imagePreview && (
                      <div className="border rounded-md overflow-hidden w-full max-w-xs">
                        <AspectRatio ratio={16 / 9}>
                          <img
                            src={imagePreview}
                            alt="Article image preview"
                            className="w-full h-full object-cover"
                          />
                        </AspectRatio>
                      </div>
                    )}

                    {!imagePreview && (
                      <div className="border border-dashed rounded-md p-8 text-center bg-muted/30 w-full max-w-xs">
                        <div className="flex flex-col items-center gap-2">
                          <ImageIcon className="h-8 w-8 text-muted-foreground" />
                          <p className="text-sm text-muted-foreground">
                            No image uploaded
                          </p>
                        </div>
                      </div>
                    )}
                  </div>
                </div>

                <div className="col-span-1 md:col-span-2">
                  <FormField
                    control={form.control}
                    name="content"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Content</FormLabel>
                        <FormControl>
                          <Textarea
                            placeholder="Article content"
                            className="min-h-[300px]"
                            {...field}
                          />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                </div>
              </div>

              <DialogFooter>
                <Button
                  type="button"
                  variant="outline"
                  onClick={() => setIsDialogOpen(false)}
                >
                  Cancel
                </Button>
                <Button
                  type="submit"
                  disabled={createMutation.isPending || editMutation.isPending}
                >
                  {createMutation.isPending || editMutation.isPending
                    ? "Saving..."
                    : currentArticle
                      ? "Update Local Article"
                      : "Create Local Article"}
                </Button>
              </DialogFooter>
            </form>
          </Form>
        </DialogContent>
      </Dialog>

      {/* Delete Confirmation Dialog */}
      <Dialog open={isDeleteDialogOpen} onOpenChange={setIsDeleteDialogOpen}>
        <DialogContent className="sm:max-w-[425px]">
          <DialogHeader>
            <DialogTitle>Confirm Deletion</DialogTitle>
          </DialogHeader>
          <div className="py-4">
            <p>
              Are you sure you want to delete the local article "
              <strong>{currentArticle?.title}</strong>"? This action cannot be
              undone.
            </p>
          </div>
          <DialogFooter>
            <Button
              type="button"
              variant="outline"
              onClick={() => setIsDeleteDialogOpen(false)}
            >
              Cancel
            </Button>
            <Button
              type="button"
              variant="destructive"
              onClick={() =>
                currentArticle && deleteMutation.mutate(currentArticle.id)
              }
              disabled={deleteMutation.isPending}
            >
              {deleteMutation.isPending
                ? "Deleting..."
                : "Delete Local Article"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

